const apiCsrfTokenElement=document.getElementById("x-csrf-token"),apiCsrfToken=apiCsrfTokenElement?.dataset?.csrfToken??"",apiDefaultHeaders={"x-csrf-token":apiCsrfToken,"Content-Type":"application/json"};async function apiBaseRequest(e,t={}){const a=await fetch(e,{headers:{...apiDefaultHeaders,...t.headers||{}},...t});if(!a.ok){const e=new Error(`HTTP ${a.status}`);throw e.response=a,e}return a}window.apiPost=(e,t,a={})=>apiBaseRequest(e,{method:"POST",body:null!=t?JSON.stringify(t):void 0,...a}),window.apiPut=(e,t,a={})=>apiBaseRequest(e,{method:"PUT",body:null!=t?JSON.stringify(t):void 0,...a}),window.apiDelete=(e,t={})=>apiBaseRequest(e,{method:"DELETE",...t}),window.apiPostNoThrow=(e,t,a={})=>fetch(e,{method:"POST",headers:{...apiDefaultHeaders,...a.headers||{}},body:null!=t?JSON.stringify(t):void 0,...a});